import{_ as a,c as n,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Inyección: Contexto Auto | opencode-supermemory","description":"Aprende inyección automática de contexto. El Agent obtiene perfil y proyecto al inicio de sesión, usa palabras clave para guardar memoria.","frontmatter":{"title":"Inyección: Contexto Auto | opencode-supermemory","sidebarTitle":"Inyección","subtitle":"Inyección: Contexto Auto","description":"Aprende inyección automática de contexto. El Agent obtiene perfil y proyecto al inicio de sesión, usa palabras clave para guardar memoria.","tags":["contexto","inyección","prompt","memoria"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"es/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"es/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),t={name:"es/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function s(r,e,c,l,d,p){return o(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="inyeccion-automatica-de-contexto-permite-que-el-agent-se-anticipe" tabindex="-1">Inyección Automática de Contexto: Permite que el Agent &quot;Se Anticipe&quot; <a class="header-anchor" href="#inyeccion-automatica-de-contexto-permite-que-el-agent-se-anticipe" aria-label="Permalink to &quot;Inyección Automática de Contexto: Permite que el Agent &quot;Se Anticipe&quot;&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><p>Al terminar esta lección, podrás:</p><ol><li><strong>Entender</strong> por qué el Agent ya conoce tus hábitos de codificación y la arquitectura del proyecto desde el principio.</li><li><strong>Dominar</strong> el &quot;modelo tridimensional&quot; de inyección de contexto (perfil de usuario, conocimiento del proyecto, memorias relevantes).</li><li><strong>Aprender</strong> a usar palabras clave (como &quot;Remember this&quot;) para intervenir activamente en el comportamiento de memoria del Agent.</li><li><strong>Configurar</strong> la cantidad de ítems inyectados, equilibrando la longitud del contexto con la riqueza de información.</li></ol><hr><h2 id="idea-central" tabindex="-1">Idea Central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea Central&quot;">​</a></h2><p>Antes del plugin de memoria, cada vez que iniciabas una nueva sesión, el Agent era una página en blanco. Tenías que repetirle: &quot;Uso TypeScript&quot;, &quot;este proyecto usa Next.js&quot;.</p><p><strong>La inyección de contexto (Context Injection)</strong> resuelve este problema. Es como insertar un &quot;informe de misión&quot; en el cerebro del Agent en el momento en que despierta.</p><h3 id="momento-de-activacion" tabindex="-1">Momento de activación <a class="header-anchor" href="#momento-de-activacion" aria-label="Permalink to &quot;Momento de activación&quot;">​</a></h3><p>opencode-supermemory es extremadamente disciplinado, solo activa la inyección automática en <strong>el primer mensaje de la sesión</strong>.</p><ul><li><strong>¿Por qué el primero?</strong> Porque es el momento clave para establecer el tono de la sesión.</li><li><strong>¿Qué pasa con los mensajes posteriores?</strong> Los mensajes posteriores no se inyectan automáticamente para evitar interferir con el flujo de la conversación, a menos que actives manualmente (ver abajo &quot;Activación por palabras clave&quot;).</li></ul><h3 id="modelo-de-inyeccion-tridimensional" tabindex="-1">Modelo de inyección tridimensional <a class="header-anchor" href="#modelo-de-inyeccion-tridimensional" aria-label="Permalink to &quot;Modelo de inyección tridimensional&quot;">​</a></h3><p>El plugin obtiene tres tipos de datos en paralelo, combinándolos en un bloque de prompt <code>[SUPERMEMORY]</code>:</p><table tabindex="0"><thead><tr><th>Dimensión de datos</th><th>Fuente</th><th>Función</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>1. Perfil de Usuario</strong> (Profile)</td><td><code>getProfile</code></td><td>Tus preferencias a largo plazo</td><td>&quot;El usuario prefiere programación funcional&quot;, &quot;prefiere funciones flecha&quot;</td></tr><tr><td><strong>2. Conocimiento del Proyecto</strong> (Project)</td><td><code>listMemories</code></td><td>Conocimiento global del proyecto actual</td><td>&quot;Este proyecto usa Clean Architecture&quot;, &quot;API en src/api&quot;</td></tr><tr><td><strong>3. Memorias Relevantes</strong> (Relevant)</td><td><code>searchMemories</code></td><td>Experiencia previa relevante con tu primera frase</td><td>Preguntas &quot;cómo arreglar este Bug&quot;, busca registros de soluciones anteriores similares</td></tr></tbody></table><hr><h2 id="¿que-se-inyecta" tabindex="-1">¿Qué se inyecta? <a class="header-anchor" href="#¿que-se-inyecta" aria-label="Permalink to &quot;¿Qué se inyecta?&quot;">​</a></h2><p>Cuando envías el primer mensaje en OpenCode, el plugin silenciosamente inserta el siguiente contenido en el System Prompt en el fondo.</p><details class="details custom-block"><summary>Clic para ver la estructura real del contenido inyectado</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>Después de que el Agent ve esta información, se comportará como un empleado veterano que ha trabajado en este proyecto durante mucho tiempo, en lugar de un nuevo pasante.</p><hr><h2 id="mecanismo-de-activacion-por-palabras-clave-nudge" tabindex="-1">Mecanismo de activación por palabras clave (Nudge) <a class="header-anchor" href="#mecanismo-de-activacion-por-palabras-clave-nudge" aria-label="Permalink to &quot;Mecanismo de activación por palabras clave (Nudge)&quot;">​</a></h2><p>Además de la inyección automática al inicio, también puedes &quot;despertar&quot; la función de memoria en cualquier momento durante la conversación.</p><p>El plugin incorpora un <strong>detector de palabras clave</strong>. Mientras tu mensaje contenga palabras de activación específicas, el plugin enviará una &quot;pista invisible&quot; (Nudge) al Agent, forzándolo a llamar la herramienta de guardado.</p><h3 id="palabras-clave-predeterminadas" tabindex="-1">Palabras clave predeterminadas <a class="header-anchor" href="#palabras-clave-predeterminadas" aria-label="Permalink to &quot;Palabras clave predeterminadas&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (ver código fuente para más)</li></ul><h3 id="ejemplo-de-interaccion" tabindex="-1">Ejemplo de interacción <a class="header-anchor" href="#ejemplo-de-interaccion" aria-label="Permalink to &quot;Ejemplo de interacción&quot;">​</a></h3><p><strong>Tú ingresas</strong>:</p><blockquote><p>Aquí el formato de respuesta de la API cambió, <strong>remember</strong> de ahora en adelante usa <code>data.result</code> en lugar de <code>data.payload</code>.</p></blockquote><p><strong>El plugin detecta &quot;remember&quot;</strong>:</p><blockquote><p>(inyecta pista en el fondo): <code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>El Agent reacciona</strong>:</p><blockquote><p>Recibido. Recordaré este cambio. <em>(llama <code>supermemory.add</code> en el fondo para guardar memoria)</em></p></blockquote><hr><h2 id="configuracion-profunda" tabindex="-1">Configuración profunda <a class="header-anchor" href="#configuracion-profunda" aria-label="Permalink to &quot;Configuración profunda&quot;">​</a></h2><p>Puedes ajustar el comportamiento de inyección modificando <code>~/.config/opencode/supermemory.jsonc</code>.</p><h3 id="elementos-de-configuracion-comunes" tabindex="-1">Elementos de configuración comunes <a class="header-anchor" href="#elementos-de-configuracion-comunes" aria-label="Permalink to &quot;Elementos de configuración comunes&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Si inyectar el perfil de usuario (predeterminado true)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Cuántas memorias del proyecto inyectar cada vez (predeterminado 10)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Aumentar permite que el Agent conozca mejor el proyecto, pero consume más Tokens</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Cuántos ítems del perfil de usuario inyectar cada vez (predeterminado 5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Palabras clave personalizadas (soporta regex)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;anota&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;guardar permanentemente&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Nota</p><p>Después de modificar la configuración, necesitas reiniciar OpenCode o recargar el plugin para que tenga efecto.</p></div><hr><h2 id="preguntas-frecuentes" tabindex="-1">Preguntas frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas frecuentes&quot;">​</a></h2><h3 id="q-¿la-informacion-inyectada-ocupa-muchos-tokens" tabindex="-1">Q: ¿La información inyectada ocupa muchos Tokens? <a class="header-anchor" href="#q-¿la-informacion-inyectada-ocupa-muchos-tokens" aria-label="Permalink to &quot;Q: ¿La información inyectada ocupa muchos Tokens?&quot;">​</a></h3><p><strong>A</strong>: Ocupa una parte, pero usualmente controlable. En configuración predeterminada (10 memorias del proyecto + 5 del perfil), aproximadamente ocupa 500-1000 Tokens. Para modelos grandes modernos (como Claude 3.5 Sonnet) con contexto de 200k, esto es mínimo.</p><h3 id="q-¿por-que-dije-remember-y-no-reacciono" tabindex="-1">Q: ¿Por qué dije &quot;remember&quot; y no reaccionó? <a class="header-anchor" href="#q-¿por-que-dije-remember-y-no-reacciono" aria-label="Permalink to &quot;Q: ¿Por qué dije &quot;remember&quot; y no reaccionó?&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>Verifica si está escrito correctamente (soporta coincidencia regex).</li><li>Confirma si la API Key está configurada correctamente (si el plugin no está inicializado, no se activará).</li><li>El Agent puede decidir ignorar (aunque el plugin lo forzó con pista, el Agent tiene la decisión final).</li></ol><h3 id="q-¿como-se-buscan-las-memorias-relevantes" tabindex="-1">Q: ¿Cómo se buscan las &quot;memorias relevantes&quot;? <a class="header-anchor" href="#q-¿como-se-buscan-las-memorias-relevantes" aria-label="Permalink to &quot;Q: ¿Cómo se buscan las &quot;memorias relevantes&quot;?&quot;">​</a></h3><p><strong>A</strong>: Se basa en búsqueda semántica del <strong>contenido de tu primer mensaje</strong>. Si tu primera frase solo dice &quot;Hi&quot;, puede que no encuentre memorias relevantes útiles, pero el &quot;conocimiento del proyecto&quot; y el &quot;perfil de usuario&quot; seguirán siendo inyectados.</p><hr><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li><strong>Inyección automática</strong> solo se activa en el primer mensaje de la sesión.</li><li><strong>Modelo tridimensional</strong> incluye perfil de usuario, conocimiento del proyecto y memorias relevantes.</li><li><strong>Activación por palabras clave</strong> te permite comandar al Agent para guardar memoria en cualquier momento.</li><li>A través del <strong>archivo de configuración</strong> puedes controlar la cantidad de información inyectada.</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../tools/">Explicación del Conjunto de Herramientas: Enseñar al Agent a Recordar</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo usar manualmente herramientas como <code>add</code>, <code>search</code>.</li><li>Cómo ver y eliminar memorias incorrectas.</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Clic para expandir y ver ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Número de línea</th></tr></thead><tbody><tr><td>Lógica de activación de inyección</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>Detección de palabras clave</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Formateo de Prompt</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>Configuración predeterminada</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>Funciones clave</strong>:</p><ul><li><code>formatContextForPrompt()</code>: Ensambla el bloque de texto <code>[SUPERMEMORY]</code>.</li><li><code>detectMemoryKeyword()</code>: Coincidencia regex de palabras clave en el mensaje del usuario.</li></ul></details><h2 id="proxima-leccion-1" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion-1" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../tools/">Explicación del Conjunto de Herramientas: Enseñar al Agent a Recordar</a></strong>.</p><p>Aprenderás:</p><ul><li>Dominar 5 modos de herramientas principales: <code>add</code>, <code>search</code>, <code>profile</code>, <code>list</code>, <code>forget</code></li><li>Cómo intervenir y corregir manualmente la memoria del Agent</li><li>Usar instrucciones en lenguaje natural para activar el guardado de memoria</li></ul></blockquote>`,57)])])}const h=a(t,[["render",s]]);export{m as __pageData,h as default};
